import React, { useEffect } from "react";
import MetaData from "./layout/MetaData";
import { useGetProductsQuery } from "../redux/api/productApi";
import ProductItem from "./product/ProductItem";
import Loader from "./layout/Loader";
import toast from "react-hot-toast";
import CustomPagination from "./layout/CustomPagination";
import { useSearchParams } from "react-router-dom";
import Filters from "./layout/Filters";

const Home = () => {
  const [searchParams] = useSearchParams();
  const page = searchParams.get("page") || 1;
  const keyword = searchParams.get("keyword") || "";

  const params = { page, keyword };
  const { data, isLoading, isError, error } = useGetProductsQuery(params);

  useEffect(() => {
    if (isError && error?.data?.message) {
      toast.error(error.data.message);
    }
  }, [isError, error]);

  if (isLoading) return <Loader />;

  return (
    <>
      <MetaData title={"Buy Best Products Online"} />

      <div className="container mt-4">
        {keyword ? (
          <div className="row">
            {/* Filters on left */}
            <div className="col-12 col-md-3 mb-4">
              <Filters />
            </div>

            {/* Products on right */}
            <div className="col-12 col-md-9">
              <h1 id="products_heading" className="text-secondary mb-4">
                Search Results for "{keyword}"
              </h1>
              <section id="products">
                <div className="row">
                  {data?.products?.length > 0 ? (
                    data.products.map((product) => (
                      <div key={product._id} className="col-6 col-lg-4 mb-4">
                        <ProductItem product={product} />
                      </div>
                    ))
                  ) : (
                    <p>No products found</p>
                  )}
                </div>
              </section>

              <CustomPagination
                resPerPage={data?.resPerPage}
                filteredProductsCount={data?.filteredProductsCount}
              />
            </div>
          </div>
        ) : (
          // Default view without filters
          <div className="row">
            <div className="col-12">
              <h1 id="products_heading" className="text-secondary mb-4">
                Latest Products
              </h1>
              <section id="products">
                <div className="row">
                  {data?.products?.map((product) => (
                    <div key={product._id} className="col-6 col-lg-3 mb-4">
                      <ProductItem product={product} />
                    </div>
                  ))}
                </div>
              </section>
              <CustomPagination
                resPerPage={data?.resPerPage}
                filteredProductsCount={data?.filteredProductsCount}
              />
            </div>
          </div>
        )}
      </div>
    </>
  );
};

export default Home;
